<dialog class="dashboard-dialog" id="biller-dialog"><button type="button" class="dialog-close" data-dialog-close aria-label="Close">&times;</button><p class="dialog-kicker">Biller account</p><h2>Link your biller account</h2><p>Billing connections will be available here once your organization has been assigned a biller account.</p><button type="button" class="dialog-action" data-dialog-close>Got it</button></dialog>
<dialog class="dashboard-dialog" id="organization-dialog"><button type="button" class="dialog-close" data-dialog-close aria-label="Close">&times;</button><p class="dialog-kicker">Organization</p><h2>{{ auth()->user()->organization?->firstname ?? auth()->user()->firstname . ' ' . auth()->user()->secondname }}</h2><p>Your organization account is active. Contact your administrator to update organization details.</p><button type="button" class="dialog-action" data-dialog-close>Close</button></dialog>
<dialog class="dashboard-dialog" id="profile-dialog"><button type="button" class="dialog-close" data-dialog-close aria-label="Close">&times;</button><p class="dialog-kicker">Profile</p><h2>{{ auth()->user()->firstname }} {{ auth()->user()->secondname }}</h2><p>{{ auth()->user()->email }}</p><button type="button" class="dialog-action" data-dialog-close>Close</button></dialog>
